func editResumeInit(resume *models.ResumeDetail, csrfToken string) string {
	type expJSON struct {
		Company     string `json:"company"`
		Role        string `json:"role"`
		Period      string `json:"period"`
		Description string `json:"description"`
	}
	type eduJSON struct {
		Institution string `json:"institution"`
		Degree      string `json:"degree"`
		Period      string `json:"period"`
	}
	type initData struct {
		Name       string    `json:"name"`
		Title      string    `json:"title"`
		Email      string    `json:"email"`
		Phone      string    `json:"phone"`
		Location   string    `json:"location"`
		Summary    string    `json:"summary"`
		Experience []expJSON `json:"experience"`
		Education  []eduJSON `json:"education"`
		Skills     []string  `json:"skills"`
	}

	experiences := make([]expJSON, len(resume.Experience))
	for i, e := range resume.Experience {
		experiences[i] = expJSON{
			Company:     e.Company,
			Role:        e.Role,
			Period:      e.Period,
			Description: e.Description,
		}
	}

	educations := make([]eduJSON, len(resume.Education))
	for i, e := range resume.Education {
		educations[i] = eduJSON{
			Institution: e.Institution,
			Degree:      e.Degree,
			Period:      e.Period,
		}
	}

	skills := make([]string, len(resume.Skills))
	for i, s := range resume.Skills {
		skills[i] = s.Name
	}

	d := initData{
		Name:       resume.PersonalName,
		Title:      resume.PersonalTitle,
		Email:      resume.Email,
		Phone:      resume.Phone,
		Location:   resume.Location,
		Summary:    resume.Summary,
		Experience: experiences,
		Education:  educations,
		Skills:     skills,
	}

	dataJSON, _ := json.Marshal(d)

	shareToken := ""
	if resume.ShareToken != nil {
		shareToken = *resume.ShareToken
	}

	hasShare := "false"
	if shareToken != "" {
		hasShare = "true"
	}

	return fmt.Sprintf(`resumeEditorInit('%s', '%s', %s, '%s', '%s', '%s', '%s')`,
		resume.ID.String(),
		csrfToken,
		string(dataJSON),
		resume.TemplateName,
		shareToken,
		hasShare,
		resume.PhotoURL,
	)
}

